import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"蔡元培故居","description":"","frontmatter":{},"headers":[],"relativePath":"history/cai-yuanpei.md","filePath":"history/cai-yuanpei.md","lastUpdated":null}'),n={name:"history/cai-yuanpei.md"};function i(o,t,s,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="蔡元培故居" tabindex="-1">蔡元培故居 <a class="header-anchor" href="#蔡元培故居" aria-label="Permalink to &quot;蔡元培故居&quot;">​</a></h1><blockquote><p>&quot;北京大学校长，&quot;思想自由，兼容并包&quot;的倡导者。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>蔡元培故居位于北京市东城区东堂子胡同75号，是蔡元培先生1917年至1923年任北京大学校长期间租住的地方。这座四合院是蔡元培先生在北京的主要居所，也是他从事教育改革和新文化运动的重要场所。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟-1小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁5号线灯市口站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区东堂子胡同75号</td></tr></tbody></table><h2 id="蔡元培简介" tabindex="-1">蔡元培简介 <a class="header-anchor" href="#蔡元培简介" aria-label="Permalink to &quot;蔡元培简介&quot;">​</a></h2><h3 id="生平" tabindex="-1">生平 <a class="header-anchor" href="#生平" aria-label="Permalink to &quot;生平&quot;">​</a></h3><p>蔡元培（1868-1940），字鹤卿，号孑民，浙江绍兴人。近代著名教育家、革命家、政治家。</p><ul><li><strong>1868年</strong>：生于浙江绍兴</li><li><strong>1892年</strong>：中进士，授翰林院编修</li><li><strong>1904年</strong>：参与创立光复会</li><li><strong>1905年</strong>：加入同盟会</li><li><strong>1912年</strong>：任南京临时政府教育总长</li><li><strong>1917年</strong>：任北京大学校长</li><li><strong>1923年</strong>：辞去北大校长职务</li><li><strong>1940年</strong>：病逝于香港</li></ul><h3 id="教育理念" tabindex="-1">教育理念 <a class="header-anchor" href="#教育理念" aria-label="Permalink to &quot;教育理念&quot;">​</a></h3><p>蔡元培提出&quot;思想自由，兼容并包&quot;的办学方针，主张：</p><ul><li><strong>思想自由</strong>：学术独立，思想自由</li><li><strong>兼容并包</strong>：包容各种学术观点</li><li><strong>美育代宗教</strong>：提倡美育教育</li><li><strong>五育并举</strong>：德智体美劳全面发展</li></ul><h2 id="故居建筑" tabindex="-1">故居建筑 <a class="header-anchor" href="#故居建筑" aria-label="Permalink to &quot;故居建筑&quot;">​</a></h2><h3 id="四合院" tabindex="-1">四合院 <a class="header-anchor" href="#四合院" aria-label="Permalink to &quot;四合院&quot;">​</a></h3><p>蔡元培故居是一座典型的北京四合院，坐北朝南。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>占地面积</strong></td><td style="text-align:left;">约800平方米</td></tr><tr><td style="text-align:left;"><strong>建筑格局</strong></td><td style="text-align:left;">三进四合院</td></tr><tr><td style="text-align:left;"><strong>正房</strong></td><td style="text-align:left;">蔡元培书房和卧室</td></tr><tr><td style="text-align:left;"><strong>厢房</strong></td><td style="text-align:left;">客房和书房</td></tr></tbody></table><h3 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h3><p>故居内设有蔡元培生平展览，包括：</p><ul><li><strong>生平照片</strong>：蔡元培各个时期的照片</li><li><strong>手稿书信</strong>：蔡元培的手稿和书信</li><li><strong>生活用品</strong>：蔡元培使用过的物品</li><li><strong>教育文献</strong>：蔡元培的教育思想和著作</li></ul><h2 id="历史意义" tabindex="-1">历史意义 <a class="header-anchor" href="#历史意义" aria-label="Permalink to &quot;历史意义&quot;">​</a></h2><h3 id="北大校长" tabindex="-1">北大校长 <a class="header-anchor" href="#北大校长" aria-label="Permalink to &quot;北大校长&quot;">​</a></h3><p>蔡元培任北大校长期间，实行&quot;思想自由，兼容并包&quot;的办学方针，聘请陈独秀、李大钊、胡适、鲁迅等新文化运动的代表人物到北大任教，使北大成为新文化运动的中心。</p><h3 id="教育改革" tabindex="-1">教育改革 <a class="header-anchor" href="#教育改革" aria-label="Permalink to &quot;教育改革&quot;">​</a></h3><p>蔡元培是中国现代教育制度的奠基人之一，他提出并实践了许多先进的教育理念，对中国现代教育产生了深远影响。</p><h3 id="新文化运动" tabindex="-1">新文化运动 <a class="header-anchor" href="#新文化运动" aria-label="Permalink to &quot;新文化运动&quot;">​</a></h3><p>蔡元培是支持新文化运动的重要人物，他为新文化运动提供了重要的平台和支持。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>故居参观（约30分钟-1小时）</strong>：</p><p>门楼 → 一进院 → 二进院 → 正房（书房、卧室） → 厢房（展览） → 三进院</p><p><strong>结合游览路线</strong>：</p><p>蔡元培故居 → 北大红楼 → 故宫 → 景山</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">5号线灯市口站C口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">103路、104路、111路等灯市口站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从王府井步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>免费参观</strong>：免费参观</li><li><strong>保持安静</strong>：保持安静</li><li><strong>结合游览</strong>：可与北大红楼、故宫一起游览</li><li><strong>了解历史</strong>：了解蔡元培的教育思想</li><li><strong>胡同体验</strong>：体验老北京胡同</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">北大红楼</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">新文化运动发源地</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">明清皇宫</td></tr><tr><td style="text-align:left;">王府井</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">商业街</td></tr><tr><td style="text-align:left;">中国美术馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">国家级美术馆</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>蔡元培故居是蔡元培先生在北京的主要居所，是他从事教育改革和新文化运动的重要场所。</p><p>蔡元培是中国现代教育制度的奠基人，他的教育思想对中国现代教育产生了深远影响。参观蔡元培故居，可以了解这位伟大教育家的生平事迹和教育理念。</p><hr><p><strong>📍 地址</strong>：北京市东城区东堂子胡同75号 <strong>📞 电话</strong>：010-65275825</p>',44)])])}const u=e(n,[["render",i]]);export{f as __pageData,u as default};
